import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableTimes, setAvailableTimes] = useState([]);

  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  const [feedbacks, setFeedbacks] = useState([]);
  const [rating, setRating] = useState("");
  const [comment, setComment] = useState("");

  const [popup, setPopup] = useState({ show: false, message: "", type: "" });

  const showPopup = (message, type = "error") => {
    setPopup({ show: true, message, type });
  };

  // GET DOCTOR
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableTimes(data.doctor.available_time_slots || []);
      });
  }, [doctor_id]);

  // GET FEEDBACK
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setFeedbacks(data));
  }, [doctor_id]);

  const avgRating =
    feedbacks.length > 0
      ? (
          feedbacks.reduce((s, f) => s + f.rating, 0) / feedbacks.length
        ).toFixed(1)
      : 0;

  // BOOK
  const handleNext = async () => {
    if (!date || !time) {
      showPopup("Please select date and time", "error");
      return;
    }

    const token = localStorage.getItem("token");
    if (!token) {
      navigate("/login");
      return;
    }

    try {
      const res = await fetch("http://127.0.0.1:8000/book-appointment/", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Token ${token}`,
        },
        body: JSON.stringify({
          doctor_id,
          appointment_date: date,
          time_slot: time,
        }),
      });

      const data = await res.json();

      if (res.ok) {
        showPopup("Appointment booked successfully!", "success");

        setTimeout(() => {
          navigate("/myappointments");
        }, 1500);
      } else {
        showPopup(data.error || "Booking failed", "error");
      }
    } catch {
      showPopup("Server error", "error");
    }
  };

  // FEEDBACK
  const handleSubmitFeedback = () => {
    if (!rating || !comment) {
      showPopup("Add rating and comment", "error");
      return;
    }

    fetch(`http://127.0.0.1:8000/doctor-feedback/${doctor_id}/`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
      body: JSON.stringify({ rating, comment }),
    })
      .then((res) => res.json())
      .then((data) => {
        setFeedbacks([data, ...feedbacks]);
        setRating("");
        setComment("");
        showPopup("Review submitted", "success");
      });
  };

  if (!doctor) return <h2 className="loading">Loading...</h2>;

  return (
    <div className="page">
      <Navbar />

      {/* ================= POPUP ================= */}
      {popup.show && (
        <div className="overlay">
          <div className={`popupCard ${popup.type}`}>
            <h3>{popup.type === "success" ? "Success" : "Alert"}</h3>
            <p>{popup.message}</p>
            <button onClick={() => setPopup({ show: false })}>
              OK
            </button>
          </div>
        </div>
      )}

      {/* ================= MAIN ================= */}
      <div className="container">

        {/* LEFT CARD */}
        <div className="doctorCard">
          <img src={doctor.image} alt="" />
          <h2>{doctor.name}</h2>
          <p>{doctor.field}</p>
          <p>{doctor.experience} Years Experience</p>
          <p>{doctor.qualification}</p>
        </div>

        {/* RIGHT SECTION */}
        <div className="bookingCard">

          <h3>Book Appointment</h3>

          <input type="date" value={date} onChange={(e) => setDate(e.target.value)} />

          <select value={time} onChange={(e) => setTime(e.target.value)}>
            <option value="">Select Time</option>
            {availableTimes.map((t, i) => (
              <option key={i}>{t}</option>
            ))}
          </select>

          <button onClick={handleNext}>Confirm Booking</button>

          {/* FEEDBACK */}
          <div className="feedback">
            <h3>Reviews ⭐ {avgRating}</h3>

            <select value={rating} onChange={(e) => setRating(e.target.value)}>
              <option value="">Rating</option>
              <option value="5">⭐⭐⭐⭐⭐</option>
              <option value="4">⭐⭐⭐⭐</option>
              <option value="3">⭐⭐⭐</option>
              <option value="2">⭐⭐</option>
              <option value="1">⭐</option>
            </select>

            <textarea
              placeholder="Write review..."
              value={comment}
              onChange={(e) => setComment(e.target.value)}
            />

            <button onClick={handleSubmitFeedback}>Submit Review</button>
          </div>

        </div>
      </div>

      <Footer />

      {/* ================= STYLE ================= */}
      <style>{`
        .page { background:#f4f6f9; min-height:100vh; }

        .container {
          display:flex;
          gap:30px;
          justify-content:center;
          padding:40px;
        }

        .doctorCard {
          width:280px;
          background:#fff;
          padding:20px;
          border-radius:15px;
          text-align:center;
          box-shadow:0 5px 15px rgba(0,0,0,0.1);
        }

        .doctorCard img {
          width:120px;
          height:120px;
          border-radius:50%;
          object-fit:cover;
        }

        .bookingCard {
          width:400px;
          background:#fff;
          padding:25px;
          border-radius:15px;
          box-shadow:0 5px 15px rgba(0,0,0,0.1);
        }

        input, select, textarea {
          width:100%;
          padding:10px;
          margin:10px 0;
          border:1px solid #ddd;
          border-radius:8px;
        }

        button {
          width:100%;
          padding:10px;
          background:#2c3e50;
          color:#fff;
          border:none;
          border-radius:8px;
          cursor:pointer;
          margin-top:10px;
        }

        button:hover { background:#1a252f; }

        .feedback { margin-top:20px; }

        /* POPUP */
        .overlay {
          position:fixed;
          top:0;left:0;
          width:100%;height:100%;
          background:rgba(0,0,0,0.6);
          display:flex;
          align-items:center;
          justify-content:center;
        }

        .popupCard {
          background:#fff;
          padding:25px;
          border-radius:12px;
          text-align:center;
          width:280px;
          box-shadow:0 10px 30px rgba(0,0,0,0.3);
        }

        .popupCard.success { border-top:5px solid #27ae60; }
        .popupCard.error { border-top:5px solid #e74c3c; }

        .loading {
          text-align:center;
          margin-top:50px;
        }
      `}</style>

    </div>
  );
}

export default Doctorprofile;

/* STYLES */
const styles = {
  container: { minHeight: "100vh", background: "#f4f6f9" },
  main: { display: "flex", justifyContent: "center", padding: "30px" },
  card: { display: "flex", background: "#fff", padding: "20px", borderRadius: "10px" },
  left: { marginRight: "20px" },
  image: { width: "150px", borderRadius: "50%" },

  input: { padding: "8px", margin: "5px", width: "100%" },
  textarea: { width: "100%", height: "80px" },

  button: { background: "#2c3e50", color: "#fff", padding: "10px" },
  submitBtn: { background: "green", color: "#fff", padding: "10px" },

  reviewContainer: { marginTop: "20px" },

  overlay: {
    position: "fixed",
    top: 0,
    left: 0,
    background: "rgba(0,0,0,0.5)",
    width: "100%",
    height: "100%",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
  },

  popupCard: {
    background: "#fff",
    padding: "20px",
    borderRadius: "10px",
  },

  popupBtn: {
    marginTop: "10px",
    padding: "5px 15px",
  },

  loading: { textAlign: "center", marginTop: "50px" },
};
